                eatTheRest = true;
                tokens.add(token);
            }
        }
        else if (token != null && token.startsWith("-") && token.length() > 2)
        {
            String opt = token.substring(1);
            if (options.hasOption(opt))
            {
                currentOption = options.getOption(opt);
                tokens.add("-" + opt);
            }
            else if (stopAtNonOption)
            {
                eatTheRest = true;
                tokens.add(token);
